import React, { useState } from "react";
import { useNavigate } from "react-router-dom";

const AddCategory = () => {
  const navigate = useNavigate();

  const [form, setForm] = useState({
    name: "",
    color: "#8b5cf6"
  });

  // 🔹 handle input
  const handleChange = (e) => {
    setForm({
      ...form,
      [e.target.name]: e.target.value
    });
  };

  // 🔹 submit
  const handleSubmit = (e) => {
    e.preventDefault();

    if (!form.name.trim()) {
      alert("Category name required ❌");
      return;
    }

    const existing =
      JSON.parse(localStorage.getItem("categories")) || [];

    // 🔥 Save FULL object (name + color)
    const updated = [...existing, form];

    localStorage.setItem("categories", JSON.stringify(updated));

    alert("Category Created ✅");
    navigate(-1);
  };

  return (
    <div className="min-h-screen bg-[#2d3561] text-white flex flex-col items-center p-6">

      {/* 🔙 Back */}
      <div className="w-full max-w-2xl">
        <button onClick={() => navigate(-1)} className="text-xl mb-4">
          ←
        </button>
      </div>

      <h2 className="text-3xl font-bold mb-6">Add Category</h2>

      <form onSubmit={handleSubmit} className="w-full max-w-xl space-y-6">

        {/* Category Name */}
        <input
          type="text"
          name="name"
          placeholder="Category name *"
          value={form.name}
          onChange={handleChange}
          required
          className="w-full px-4 py-4 rounded-2xl bg-white/10 border border-white/20 outline-none"
        />

        {/* 🔥 FULL COLOR PICKER BOX */}
        <div className="w-full p-4 rounded-2xl bg-white/10 border border-white/20 space-y-4">

          <p className="text-sm text-white/70">Pick Category Color</p>

          {/* Big Color Picker */}
          <input
            type="color"
            value={form.color}
            onChange={(e) =>
              setForm({ ...form, color: e.target.value })
            }
            className="w-full h-20 rounded-xl cursor-pointer border-none"
          />

          {/* HEX Input */}
          <input
            type="text"
            value={form.color}
            onChange={(e) =>
              setForm({ ...form, color: e.target.value })
            }
            placeholder="#8b5cf6"
            className="w-full px-4 py-2 rounded bg-white/10 border border-white/20 outline-none text-white"
          />

          {/* Preview */}
          <div className="flex items-center gap-3">
            <div
              className="w-10 h-10 rounded-full border border-white"
              style={{ backgroundColor: form.color }}
            />
            <span className="text-sm text-white/70">
              Preview Color
            </span>
          </div>

        </div>

        {/* Button */}
        <button
          type="submit"
          className="w-full py-4 rounded-full bg-gradient-to-r from-purple-500 to-pink-500 text-white text-xl font-semibold hover:scale-105 transition"
        >
          Create Category
        </button>

      </form>
    </div>
  );
};

export default AddCategory;
